&#34;false&#34;&lt;/span&gt;）&lt;span class=&#34;token operator&#34;&gt;--&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;aop&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;aspectj&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;autoproxy proxy&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;target&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;class&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;true&#34;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h1 id=&#34;12-整合mybatis&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#12-整合mybatis&#34;&gt;#&lt;/a&gt; 12、整合 Mybatis&lt;/h1&gt;
&lt;p&gt;步骤：&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;导入相关 jar 包
